  1→/**
  2→ * Intent Node Acceptance Test Kit
  3→ *
  4→ * Extends the orchestrator-test-kit with intent-specific helpers.
  5→ * All helpers use business language -- no technical jargon in function names.
  6→ *
  7→ * Driving ports:
  8→ *   POST /api/intents/:id/evaluate  (SurrealQL EVENT target)
  9→ *   POST /api/intents/:id/veto      (human veto)
 10→ *   MCP tools: create_intent, submit_intent, get_intent_status
 11→ */
 12→import { RecordId, type Surreal } from "surrealdb";
 13→
 14→// Re-export everything from orchestrator-test-kit
 15→export {
 16→  setupOrchestratorSuite,
 17→  createTestUser,
 18→  createTestWorkspace,
 19→  createReadyTask,
 20→  createTestProject,
 21→  getTestUserBearerToken,
 22→  fetchJson,
 23→  fetchRaw,
 24→  type OrchestratorTestRuntime,
 25→  type TestUser,
 26→  type TestUserWithToken,
 27→  type TestWorkspace,
 28→  type TestTask,
 29→  type TestProject,
 30→} from "../coding-agent-orchestrator/orchestrator-test-kit";
 31→
 32→import {
 33→  fetchJson,
 34→  type TestUser,
 35→  type TestUserWithToken,
 36→} from "../coding-agent-orchestrator/orchestrator-test-kit";
 37→
 38→// ---------------------------------------------------------------------------
 39→// Intent-Specific Types
 40→// ---------------------------------------------------------------------------
 41→
 42→export type IntentStatus =
 43→  | "draft"
 44→  | "pending_auth"
 45→  | "pending_veto"
 46→  | "authorized"
 47→  | "executing"
 48→  | "completed"
 49→  | "vetoed"
 50→  | "failed";
 51→
 52→export type ActionSpec = {
 53→  provider: string;
 54→  action: string;
 55→  params?: Record<string, unknown>;
 56→};
 57→
 58→export type BudgetLimit = {
 59→  amount: number;
 60→  currency: string;
 61→};
 62→
 63→export type EvaluationResult = {
 64→  decision: "APPROVE" | "REJECT";
 65→  risk_score: number;
 66→  reason: string;
 67→  evaluated_at: string;
 68→  policy_only: boolean;
 69→};
 70→
 71→export type IntentRecord = {
 72→  id: RecordId<"intent">;
 73→  goal: string;
 74→  reasoning: string;
 75→  status: IntentStatus;
 76→  priority: number;
 77→  action_spec: ActionSpec;
 78→  budget_limit?: BudgetLimit;
 79→  evaluation?: EvaluationResult;
 80→  veto_expires_at?: string;
 81→  veto_reason?: string;
 82→  error_reason?: string;
 83→  trace_id: RecordId<"trace">;
 84→  created_at: string;
 85→  updated_at?: string;
 86→};
 87→
 88→export type CreateIntentOptions = {
 89→  goal: string;
 90→  reasoning: string;
 91→  priority?: number;
 92→  action_spec: ActionSpec;
 93→  budget_limit?: BudgetLimit;
 94→  taskId?: string;
 95→};
 96→
 97→// ---------------------------------------------------------------------------
 98→// Domain Helpers -- Business Language Layer
 99→// ---------------------------------------------------------------------------
100→
101→/**
102→ * Creates a draft intent directly in the database.
103→ * Used as a Given-step precondition for scenarios that start
104→ * with an intent already in draft status.
105→ */
106→export async function createDraftIntent(
107→  surreal: Surreal,
108→  workspaceId: string,
109→  requesterId: string,
110→  opts: CreateIntentOptions,
111→): Promise<{ intentId: string; intentRecord: RecordId<"intent"> }> {
112→  const intentId = `intent-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
113→  const intentRecord = new RecordId("intent", intentId);
114→  const workspaceRecord = new RecordId("workspace", workspaceId);
115→  const requesterRecord = new RecordId("identity", requesterId);
116→
117→  // Create trace record for the intent
118→  const traceId = `trace-${intentId}`;
119→  const traceRecord = new RecordId("trace", traceId);
120→  await surreal.query(`CREATE $trace CONTENT $content;`, {
121→    trace: traceRecord,
122→    content: {
123→      type: "intent_submission",
124→      actor: requesterRecord,
125→      workspace: workspaceRecord,
126→      created_at: new Date(),
127→    },
128→  });
129→
130→  const content: Record<string, unknown> = {
131→    goal: opts.goal,
132→    reasoning: opts.reasoning,
133→    status: "draft",
134→    priority: opts.priority ?? 50,
135→    action_spec: opts.action_spec,
136→    trace_id: traceRecord,
137→    requester: requesterRecord,
138→    workspace: workspaceRecord,
139→    created_at: new Date(),
140→  };
141→
142→  if (opts.budget_limit) {
143→    content.budget_limit = opts.budget_limit;
144→  }
145→
146→  await surreal.query(`CREATE $intent CONTENT $content;`, {
147→    intent: intentRecord,
148→    content,
149→  });
150→
151→  // Link to originating task if provided
152→  if (opts.taskId) {
153→    const taskRecord = new RecordId("task", opts.taskId);
154→    await surreal.query(
155→      `RELATE $intent->triggered_by->$task SET created_at = time::now();`,
156→      { intent: intentRecord, task: taskRecord },
157→    );
158→  }
159→
160→  return { intentId, intentRecord };
161→}
162→
163→/**
164→ * Submits a draft intent for authorization.
165→ * Transitions draft -> pending_auth, which triggers the SurrealQL EVENT.
166→ */
167→export async function submitIntent(
168→  surreal: Surreal,
169→  intentId: string,
170→): Promise<void> {
171→  const intentRecord = new RecordId("intent", intentId);
172→  await surreal.query(
173→    `UPDATE $intent SET status = "pending_auth", updated_at = time::now();`,
174→    { intent: intentRecord },
175→  );
176→}
177→
178→/**
179→ * Queries the current status of an intent from the database.
180→ */
181→export async function getIntentStatus(
182→  surreal: Surreal,
183→  intentId: string,
184→): Promise<IntentStatus> {
185→  const intentRecord = new RecordId("intent", intentId);
186→  const rows = (await surreal.query(`SELECT status FROM $intent;`, {
187→    intent: intentRecord,
188→  })) as Array<Array<{ status: IntentStatus }>>;
189→  const result = rows[0]?.[0];
190→  if (!result) {
191→    throw new Error(`Intent ${intentId} not found`);
192→  }
193→  return result.status;
194→}
195→
196→/**
197→ * Queries the full intent record from the database.
198→ */
199→export async function getIntentRecord(
200→  surreal: Surreal,
201→  intentId: string,
202→): Promise<IntentRecord> {
203→  const intentRecord = new RecordId("intent", intentId);
204→  const rows = (await surreal.query(`SELECT * FROM $intent;`, {
205→    intent: intentRecord,
206→  })) as Array<Array<IntentRecord>>;
207→  const result = rows[0]?.[0];
208→  if (!result) {
